void hotspotOpt1(float *p, float* tIn, float *tOut, float sdc,
                 int nx, int ny, int nz,
                 float ce, float cw, 
                 float cn, float cs,
                 float ct, float cb, 
                 float cc) 
{
  float amb_temp = 80.0;
  int xy = nx * ny;

  #pragma omp parallel for collapse(2)
  for (int j = 0; j < ny; j++) {
    for (int i = 0; i < nx; i++) {
      int c = i + j * nx;

      int W = (i == 0)        ? c : c - 1;
      int E = (nx-1 == i)     ? c : c + 1;
      int N = (j == 0)        ? c : c - nx;
      int S = (ny-1 == j)     ? c : c + nx;

      float temp1, temp2, temp3;
      temp1 = temp2 = tIn[c];
      temp3 = tIn[c+xy];
      tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
        + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;
      c += xy;
      W = W + (xy);
      E = E + (xy);
      N = N + (xy);
      S += xy;

      for (int k = 1; nz-1 > k; ++k) {
          temp1 = temp2;
          temp2 = temp3;
          temp3 = tIn[c+xy];
          tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
            + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;
          c += xy;
          W = W + (xy);
          E += xy;
          N = N + (xy);
          S = S + (xy);
      }
      temp1 = temp2;
      temp2 = temp3;
      tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
        + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;
    }
  }
}

