void resize(fp* input, int input_rows, int input_cols, fp* output, int output_rows, int output_cols, int major) {
    if (major == 0) {
        for (int i = 0, i2 = 0; i < output_rows; i++, i2++) {
            if (i2 >= input_rows) i2 = i2 - input_rows;
            for (int j = 0, j2 = 0; j < output_cols; j++, j2++) {
                if (j2 >= input_cols) j2 = j2 - input_cols;
                output[i * output_cols + j] = input[i2 * input_cols + j2];
            }
        }
    } else {
        for (int j = 0, j2 = 0; j < output_cols; j++, j2++) {
            if (j2 >= input_cols) j2 = j2 - input_cols;
            for (int i = 0, i2 = 0; i < output_rows; i++, i2++) {
                if (i2 >= input_rows) i2 = i2 - input_rows;
                output[j * output_rows + i] = input[j2 * input_rows + i2];
            }
        }
    }
}

void extract_kernel(long d_Ne, fp* d_I) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = exp(d_I[ei] / 255);
    }
}

void prepare_kernel(long d_Ne, fp* d_I, fp* d_sums, fp* d_sums2) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei] * d_I[ei];
    }
}

void reduce_kernel(long d_Ne, long d_no, int d_mul, fp* d_sums, fp* d_sums2, int gridDim) {
    int nf = NUMBER_THREADS - (gridDim * NUMBER_THREADS - d_no);
    int df = 0;

    #pragma omp parallel for
    for (int bx = 0; bx < gridDim; bx++) {
        fp d_psum[NUMBER_THREADS];
        fp d_psum2[NUMBER_THREADS];

        for (int tx = 0; tx < NUMBER_THREADS; tx++) {
            int ei = bx * NUMBER_THREADS + tx;
            if (ei < d_no) {
                d_psum[tx] = d_sums[ei * d_mul];
                d_psum2[tx] = d_sums2[ei * d_mul];
            }
        }

        if (nf == NUMBER_THREADS) {
            for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                for (int tx = 0; tx < NUMBER_THREADS; tx++) {
                    if ((tx + 1) % i == 0) {
                        d_psum[tx] = d_psum[tx] + d_psum[tx - i/2];
                        d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i/2];
                    }
                }
            }

            d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[NUMBER_THREADS - 1];
            d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[NUMBER_THREADS - 1];
        } else {
            if (bx != (gridDim - 1)) {
                for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                    for (int tx = 0; tx < NUMBER_THREADS; tx++) {
                        if ((tx + 1) % i == 0) {
                            d_psum[tx] = d_psum[tx] + d_psum[tx - i/2];
                            d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i/2];
                        }
                    }
                }

                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[NUMBER_THREADS - 1];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[NUMBER_THREADS - 1];
            } else {
                for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                    if (nf >= i) df = i;
                }

                for (int i = 2; i <= df; i = 2 * i) {
                    for (int tx = 0; tx < NUMBER_THREADS; tx++) {
                        if ((tx + 1) % i == 0 && tx < df) {
                            d_psum[tx] = d_psum[tx] + d_psum[tx - i/2];
                            d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i/2];
                        }
                    }
                }

                for (int i = (bx * NUMBER_THREADS) + df; i < (bx * NUMBER_THREADS) + nf; i++) {
                    d_psum[df - 1] = d_psum[df - 1] + d_sums[i];
                    d_psum2[df - 1] = d_psum2[df - 1] + d_sums2[i];
                }

                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[df - 1];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[df - 1];
            }
        }
    }
}

void srad_kernel(fp d_lambda, int d_Nr, int d_Nc, long d_Ne,
                 int* d_iN, int* d_iS, int* d_jE, int* d_jW,
                 fp* d_dN, fp* d_dS, fp* d_dW, fp* d_dE,
                 fp d_q0sqr, fp* d_c, fp* d_I) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        int row = (ei + 1) % d_Nr - 1;
        int col = (ei + 1) / d_Nr + 1 - 1;
        if ((ei + 1) % d_Nr == 0) {
            row = d_Nr - 1;
            col = col - 1;
        }

        fp d_Jc = d_I[ei];
        fp d_dN_loc = d_I[d_iN[row] + d_Nr * col] - d_Jc;
        fp d_dS_loc = d_I[d_iS[row] + d_Nr * col] - d_Jc;
        fp d_dW_loc = d_I[row + d_Nr * d_jW[col]] - d_Jc;
        fp d_dE_loc = d_I[row + d_Nr * d_jE[col]] - d_Jc;

        fp d_G2 = (d_dN_loc * d_dN_loc + d_dS_loc * d_dS_loc +
                   d_dW_loc * d_dW_loc + d_dE_loc * d_dE_loc) / (d_Jc * d_Jc);
        fp d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;

        fp d_num = (0.5 * d_G2) - ((1.0 / 16.0) * (d_L * d_L));
        fp d_den = 1 + (0.25 * d_L);
        fp d_qsqr = d_num / (d_den * d_den);

        d_den = (d_qsqr - d_q0sqr) / (d_q0sqr * (1 + d_q0sqr));
        fp d_c_loc = 1.0 / (1.0 + d_den);

        if (d_c_loc < 0) d_c_loc = 0;
        else if (d_c_loc > 1) d_c_loc = 1;

        d_dN[ei] = d_dN_loc;
        d_dS[ei] = d_dS_loc;
        d_dW[ei] = d_dW_loc;
        d_dE[ei] = d_dE_loc;
        d_c[ei] = d_c_loc;
    }
}

void srad2_kernel(fp d_lambda, int d_Nr, int d_Nc, long d_Ne,
                  int* d_iN, int* d_iS, int* d_jE, int* d_jW,
                  fp* d_dN, fp* d_dS, fp* d_dE, fp* d_dW,
                  fp* d_c, fp* d_I) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        int row = (ei + 1) % d_Nr - 1;
        int col = (ei + 1) / d_Nr + 1 - 1;
        if ((ei + 1) % d_Nr == 0) {
            row = d_Nr - 1;
            col = col - 1;
        }

        fp d_cN = d_c[ei];
        fp d_cS = d_c[d_iS[row] + d_Nr * col];
        fp d_cW = d_c[ei];
        fp d_cE = d_c[row + d_Nr * d_jE[col]];

        fp d_D = d_cN * d_dN[ei] + d_cS * d_dS[ei] +
                 d_cW * d_dW[ei] + d_cE * d_dE[ei];

        d_I[ei] = d_I[ei] + 0.25 * d_lambda * d_D;
    }
}

void compress_kernel(long d_Ne, fp* d_I) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = log(d_I[ei]) * 255;
    }
}

void kernel_gpu_opencl_wrapper(fp* image, int Nr, int Nc, long Ne,
                               int niter, fp lambda, long NeROI,
                               int* iN, int* iS, int* jE, int* jW,
                               int iter, int mem_size_i, int mem_size_j) {

    fp* d_I = image;
    fp* d_sums = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_sums2 = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dN = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dS = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dW = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dE = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_c = (fp*)malloc(sizeof(fp) * Ne);

    extract_kernel(Ne, d_I);

    fp total, total2, meanROI, meanROI2, varROI, q0sqr;
    int blocks_x = Ne / NUMBER_THREADS;
    if (Ne % NUMBER_THREADS != 0) blocks_x++;

    printf("Iterations Progress: hidden\n");

    for (iter = 0; iter < niter; iter++) {
        prepare_kernel(Ne, d_I, d_sums, d_sums2);

        int blocks2_work_size = blocks_x;
        long no = Ne;
        int mul = 1;

        while (blocks2_work_size != 0) {
            reduce_kernel(Ne, no, mul, d_sums, d_sums2, blocks2_work_size);

            no = blocks2_work_size;
            if (blocks2_work_size == 1) {
                blocks2_work_size = 0;
            } else {
                mul = mul * NUMBER_THREADS;
                blocks_x = blocks2_work_size / NUMBER_THREADS;
                if (blocks2_work_size % NUMBER_THREADS != 0) blocks_x++;
                blocks2_work_size = blocks_x;
            }
        }

        total = d_sums[0];
        total2 = d_sums2[0];

        meanROI = total / (fp)(NeROI);
        meanROI2 = meanROI * meanROI;
        varROI = (total2 / (fp)(NeROI)) - meanROI2;
        q0sqr = varROI / meanROI2;

        srad_kernel(lambda, Nr, Nc, Ne, iN, iS, jE, jW,
                    d_dN, d_dS, d_dW, d_dE, q0sqr, d_c, d_I);
        srad2_kernel(lambda, Nr, Nc, Ne, iN, iS, jE, jW,
                     d_dN, d_dS, d_dE, d_dW, d_c, d_I);
    }

    printf("\n");

    compress_kernel(Ne, d_I);

    free(d_sums);
    free(d_sums2);
    free(d_dN);
    free(d_dS);
    free(d_dW);
    free(d_dE);
    free(d_c);
}

